from microbit import *

while True:
    light = display.read_light_level()  # 0-255
    temp  = temperature()               # Celsius degrees

    display.scroll('L:' + str(light) + ' T:' + str(temp), delay=60)

    if light < 50:
        display.show(Image.ASLEEP)     # Very dark
    elif temp > 28:
        display.show(Image.SURPRISED)  # Very hot
    else:
        display.show(Image.HAPPY)
    sleep(1500)

