# WEATHER STATION — Level 2
from microbit import *

readings = []

def calibrated_temp():
    return temperature() - 3

def average(lst):
    if len(lst) == 0: return 0
    return sum(lst) / len(lst)

def record():
    t = calibrated_temp()
    readings.append(t)
    if len(readings) > 10: readings.pop(0)
    return t

def show_stats():
    if not readings:
        display.scroll('No data'); return
    display.scroll('Avg:' + str(round(average(readings), 1)))
    display.scroll('Max:' + str(max(readings)))
    display.scroll('Min:' + str(min(readings)))

while True:
    t = record()
    display.scroll(str(t) + 'C', delay=70)
    if button_a.was_pressed(): show_stats()
    sleep(5000)

