# Giant buttons with pins
from microbit import *

# Pins 0 and 1 as inputs (buttons)
# Connect pin 0 to GND to press GIANT button (e.g., clip to pin 0, another to GND/P0)
# Connect pin 1 to GND to press GIANT button (e.g., clip to pin 1, another to GND/P1)

while True:
    if pin0.is_touched(): # Detects if pin is connected to GND (pressed)
        display.show(Image.YES)
    elif pin1.is_touched():
        display.show(Image.NO)
    else:
        display.clear()
    sleep(50)
